import { motion } from "framer-motion";
import styles from "./Skills.module.css";

const skills = [
  { name: "React", rotate: -5, x: -10, y: 5 },
  { name: "Next.js", rotate: 5, x: 10, y: -5 },
  { name: "TypeScript", rotate: -3, x: 5, y: -8 },
  { name: "JavaScript", rotate: 3, x: -5, y: 8 },
  { name: "HTML", rotate: 0, x: 0, y: 0 },
  { name: "CSS", rotate: -2, x: 3, y: -3 },
];

export default function Skills() {
  return (
    <div className={styles.skills}>
      {skills.map((skill) => (
        <motion.div
          key={skill.name}
          className={styles.skill}
          whileHover={{
            scale: 1.3,
            rotate: skill.rotate,
            x: skill.x,
            y: skill.y,
            boxShadow: "0 8px 20px rgba(255,255,255,0.3)",
          }}
          transition={{ type: "spring", stiffness: 300, damping: 10 }}
        >
          {skill.name}
        </motion.div>
      ))}
    </div>
  );
}
